form:Form.form:Scripts:
		function ACEPTAR_NEW_EDIT(meThis)
 {
	if (CtrlExists('f_min_inc') && CtrlExists('f_max_inc'))  
 	{          
		if (Ctrl('f_min_inc').GetXValue() != "" && Ctrl('f_max_inc').GetXValue() != "")
  		{
			if (Ctrl('f_min_inc').GetXValue() > Ctrl('f_max_inc').GetXValue())
			{
				meThis.SetError("La fecha máxima de inscripción debe ser posterior a la fecha mínima de inscripción");
				return false;						
			}
  		}
  	}


 	if (CtrlExists('f_req')) {

 		if (CtrlExists('f_min_inc'))
		{  
			if (Ctrl('f_min_inc').GetXValue() != "" && Ctrl('f_req').GetXValue() != "")
	  		{ 	
	 			if (Ctrl('f_min_inc').GetXValue() < Ctrl('f_req').GetXValue())  
				{	
					meThis.SetError("La fecha mínima de inscripción debe ser posterior a la fecha del Requerimiento");
					return false;						
				}
	  		}
	 	}

	  	if (CtrlExists('f_max_inc')) 
	 	{          		
			if (Ctrl('f_max_inc').GetXValue() != "" && Ctrl('f_req').GetXValue() != "")
	  		{
				if (Ctrl('f_max_inc').GetXValue() < Ctrl('f_req').GetXValue())		
				{
					meThis.SetError("La fecha máxima de inscripción debe ser posterior a la fecha del Requerimiento");
					return false;						
				}
			}
	  	}

	  	if (CtrlExists('f_inicio'))
	 	{          
			if (Ctrl('f_inicio').GetXValue() != "" && Ctrl('f_req').GetXValue() != "")
	  		{
	    		if (Ctrl('f_inicio').GetXValue() < Ctrl('f_req').GetXValue())	
				{
					meThis.SetError("La fecha de inicio debe ser posterior a la fecha del Requerimiento");
					return false;						
				}				
			} 
		}
	}


  	if (CtrlExists('f_inicio')) {

	  	if (CtrlExists('f_min_inc'))
	 	{ 
			if (Ctrl('f_min_inc').GetXValue() != "" && Ctrl('f_inicio').GetXValue() != "")
	  		{
				if (Ctrl('f_min_inc').GetXValue() < Ctrl('f_inicio').GetXValue())	
				{
					meThis.SetError("La fecha mínima de inscripción debe ser posterior a la fecha de inicio del Requerimiento");
					return false;						
				}
			}
	  	}

		if (CtrlExists('f_max_inc'))
	 	{          	
			if (Ctrl('f_max_inc').GetXValue() != "" && Ctrl('f_inicio').GetXValue() != "")
	  		{
				if (Ctrl('f_max_inc').GetXValue() < Ctrl('f_inicio').GetXValue())	
				{
					meThis.SetError("La fecha máxima de inscripción debe ser posterior a la fecha de inicio del Requerimiento");
					return false;						
				}
	 		}  
		}
	}

	return true;

 }  

function LoadForm()
{
	if (Ctrl('ca_estado').GetXValue() == "I")
	{	
		CtrlEnabled('DELETE',false);
		if (Ctrl('main').GetMode() == "SHOW")
		{
			CtrlEnabled('cerrar', true);	
			CtrlEnabled('anular', false);	 	 
			CtrlEnabled('iniciar', false);
		}
	}

	if (Ctrl('ca_estado').GetXValue() == "A")
	{
		if (Ctrl('main').GetMode() != "NEW")
		{
			CtrlEnabled('DELETE', true);  
		}
		if (Ctrl('main').GetMode() == "SHOW")
		{	
			CtrlEnabled('cerrar', false);
			CtrlEnabled('iniciar', true);
			CtrlEnabled('anular', true);			 	
		}
	}
	if (Ctrl('ca_estado').GetXValue() == "C")
	{
		if (Ctrl('main').GetMode() == "LIST")
		{
		CtrlEnabled('EDIT', false);
		CtrlEnabled('DELETE', false);	
		}
	}

	if (Ctrl('ca_estado').GetXValue() == "C")
	{
		if (Ctrl('main').GetMode() == "SHOW")
		{
			CtrlEnabled('iniciar', false);
			CtrlEnabled('cerrar', false);
			CtrlEnabled('anular', false);
		}

		CtrlEnabled('EDIT', false);
		CtrlEnabled('DELETE', false);	

	}	

	if (Ctrl('ca_estado').GetXValue() == "N")
	{
	if (Ctrl('main').GetMode() == "SHOW")
	{
		CtrlEnabled('iniciar', true);
		CtrlEnabled('cerrar', false);
		CtrlEnabled('anular', true);
	}
	CtrlEnabled('EDIT', false);
	CtrlEnabled('DELETE', true);			 
	}

	CtrlEnabled('f_req', false);
	if (Ctrl('main').GetMode() == "NEW")
	{
		CtrlEnabled('f_req', true);
	} 
  //CtrlEnabled('d_consultora', false);
  //Ctrl("d_consultora").SetXValue("");
}

function SetConsultora()
{
  //CtrlEnabled('d_consultora', false);

	if(Ctrl("c_tipo_req").GetXValue()!="1")
	{
		if (Ctrl('main').GetMode() == "EDIT" || Ctrl('main').GetMode() == "NEW")
		{
		CtrlEnabled('d_consultora', true);	                                      
		} 
	} 
	else
	{
		CtrlEnabled('d_consultora', false);
		Ctrl("d_consultora").SetXValue("");
	}
}

function VIEW()
{
	var param='<SOLIC id="' +Ctrl("oi_solic_per").GetXValue()+ '"/>';
	openNewFlow("NucleusRH.SancorRH.Postulantes.SolicitudesPersonal.flow","view",param,new ObjetoActualizador(),"L");
}

